import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Page/page-settings.md","filePath":"hi/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"hi/Page/page-settings.md"};function i(n,t,l,g,s,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings site display, upload page defaults, background images और admin panel appearance control करती हैं।</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>Browser tab में दिखने वाला title।</td></tr><tr><td>Site icon</td><td>Browser tab में दिखने वाला छोटा icon।</td></tr><tr><td>ImgBed name</td><td>Frontend pages पर दिखने वाला नाम।</td></tr><tr><td>ImgBed logo</td><td>Frontend pages पर दिखने वाली logo image।</td></tr><tr><td>Logo link</td><td>Logo या avatar click करने पर खुलने वाला URL।</td></tr><tr><td>Background switch interval</td><td>Multiple backgrounds के rotation interval, milliseconds में। <code>60000</code> मतलब 60 seconds।</td></tr><tr><td>Background opacity</td><td>Background image opacity <code>0</code> से <code>1</code> तक। Lower values हल्की दिखती हैं।</td></tr><tr><td>Default URL prefix</td><td>Image links generate करते समय इस्तेमाल होने वाला prefix। Empty होने पर current site domain इस्तेमाल होता है।</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>Upload page के top पर दिखने वाला announcement। HTML supported है।</td></tr><tr><td>Default upload channel</td><td>Upload page पर default selected upload channel। Smart Dispatch भी चुन सकते हैं।</td></tr><tr><td>Default upload directory</td><td>Default upload directory, जैसे <code>/user/</code>। Empty या <code>/</code> मतलब root।</td></tr><tr><td>Default naming method</td><td>Upload के बाद filename generate करने की default strategy। नीचे देखें।</td></tr><tr><td>Convert to WebP by default</td><td>Upload से पहले images को WebP में convert करता है।</td></tr><tr><td>Enable compression by default</td><td>Upload से पहले browser में locally images compress करता है।</td></tr><tr><td>Default compression threshold</td><td>Image इस size से बड़ी होने पर automatically compress होगी, MB में।</td></tr><tr><td>Default target size</td><td>Compression के बाद target file size, MB में।</td></tr><tr><td>Login page background</td><td>User login page की background image।</td></tr><tr><td>Upload page background</td><td>Upload page की background image।</td></tr><tr><td>Footer portal link</td><td>Footer portal button click करने पर खुलने वाला URL।</td></tr><tr><td>Hide footer</td><td>Enabled होने पर frontend footer hide करता है।</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>Admin login page की background image।</td></tr><tr><td>Admin background</td><td>Admin pages की background image। एक image URL या multiple URLs इस्तेमाल करें।</td></tr><tr><td>Image loading mode</td><td>Admin file list के लिए preview loading mode। Original original images load करता है। Smart loading public images के लिए thumbnails और restricted images के लिए originals prefer करता है।</td></tr><tr><td>Thumbnail source</td><td>Thumbnails generate करने वाली service: wsrv.nl, Cloudflare Image Resizing या WordPress Photon। Cloudflare Image Resizing select करने से पहले Cloudflare में enabled होना चाहिए।</td></tr><tr><td>Live2D widget</td><td>Admin panel में Live2D character दिखाता है।</td></tr><tr><td>Firework click effect</td><td>Page click करने पर firework effect दिखाता है।</td></tr><tr><td>Star cursor trail</td><td>Mouse move करने पर star trail दिखाता है।</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background और admin login background ये formats support करते हैं:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Bing wallpaper rotation इस्तेमाल करता है।</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Multiple images rotate करता है।</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Single background image इस्तेमाल करता है।</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Random image API link इस्तेमाल करता है। Other Settings में अपना Random Image API configure करें, फिर generated random image link को single-background entry के रूप में यहाँ paste करें।</td></tr></tbody></table><p>Admin background image URLs support करता है। Page पर prompt के अनुसार multiple URLs English commas से separate किए जा सकते हैं। Empty होने पर default background इस्तेमाल होता है।</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, जैसे <code>1760000000000_cat.png</code>।</td></tr><tr><td>Prefix only</td><td>केवल time-random prefix और extension, जैसे <code>1760000000000.png</code>।</td></tr><tr><td>Original name only</td><td>Original filename रखता है, जैसे <code>cat.png</code>। Duplicate होने पर ImgBed <code>(1)</code>, <code>(2)</code> आदि जोड़ता है।</td></tr><tr><td>Short link</td><td>8-character short ID और extension इस्तेमाल करता है, जैसे <code>a1b2c3d4.png</code>।</td></tr></tbody></table>',14)])])}const u=e(o,[["render",i]]);export{p as __pageData,u as default};
